#include <stdio.h>
#include <stdlib.h>

struct Node {
    int val;
    struct Node* next;
};

struct Node* newNode(int v) {
    struct Node* n = (struct Node*)malloc(sizeof(struct Node));
    n->val = v;
    n->next = NULL;
    return n;
}

struct Node* reverseList(struct Node* head) {
    struct Node* prev = NULL;
    while (head) {
        struct Node* nxt = head->next;
        head->next = prev;
        prev = head;
        head = nxt;
    }
    return prev;
}

int isPalindrome(struct Node* head) {
    if (!head || !head->next) return 1;
    struct Node *slow = head, *fast = head;
    while (fast->next && fast->next->next) {
        slow = slow->next;
        fast = fast->next->next;
    }
    struct Node* second = reverseList(slow->next);
    struct Node* first = head;
    int ok = 1;
    while (second) {
        if (first->val != second->val) { ok = 0; break; }
        first = first->next;
        second = second->next;
    }
    // optional: restore list (not required)
    return ok;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        struct Node *head = NULL, *tail = NULL;
        for (int i = 0; i < N; ++i) {
            int x; scanf("%d", &x);
            struct Node* nd = newNode(x);
            if (!head) head = tail = nd; else { tail->next = nd; tail = nd; }
        }
        printf(isPalindrome(head) ? "YES\n" : "NO\n");
        while (head) { struct Node* tmp = head; head = head->next; free(tmp); }
    }
    return 0;
}

