    while (head) {
        Node* nxt = head->next;
        head->next = prev;
        prev = head;
        head = nxt;
    }
    return prev;
}

bool isPalindrome(Node* head) {
    if (!head || !head->next) return true;
    Node *slow = head, *fast = head;
    while (fast->next && fast->next->next) {
        slow = slow->next;
        fast = fast->next->next;
    }
    Node* second = reverseList(slow->next);
    Node* first = head;
    bool ok = true;
    while (second) {
        if (first->val != second->val) { ok = false; break; }
        first = first->next;
        second = second->next;
    }
    return ok;
}

