#!/usr/bin/env python3
import sys

def is_palindrome(vals):
    i, j = 0, len(vals) - 1
    while i < j:
        if vals[i] != vals[j]:
            return False
        i += 1
        j -= 1
    return True

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        arr = [int(next(it)) for _ in range(N)]
        out.append('YES' if is_palindrome(arr) else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

